["spellDescriptionCache"] = {
[1249595] = {
["time"] = 1775244338,
["description"] = "Senn eminates holy power for 15 sec, blessing players within 20 yards. Every 1 sec, this applies protection to nearby players that absorbs 19,850 Midnight Flames damage. If present, Bellamy and/or Lightblood increase the amount of absorb granted. 25% of Midnight Flames damage pierces this absorb.\r\n\r\nAdditionally, gaining Radiant Barrier consumes Midnight Manifestation, spawning a Manifestation of Midnight or infusing an existing Manifestation for each aura stack consumed.",
},
[1246132] = {
["time"] = 1774316355,
["description"] = "Chimaerus is protected by the shroud of its den while in the air, reducing damage taken by 99%.",
},
[1220618] = {
["time"] = 1773193474,
["description"] = "The Plexus Sentinel relocates, pushing players away and activating the |cffffffffArcanomatrix Atomizer|r. The Atomizer slowly passes over the chamber, Atomizing any players  it contacts.\r\n\r\nAfter relocating, The Plexus Sentinel begins channelling |cffffffffProtocol: Purge|r and gains a shield that absorbs damage. Breaking this shield interrupts |cffffffffProtocol: Purge|r.",
},
[1258610] = {
["time"] = 1774316355,
["description"] = "Chimaerus unleashes an unearthly roar, inflicting 144,425 Nature damage to all players and causing Manifestations to emerge throughout the Rift.",
},
[1255738] = {
["time"] = 1774843171,
["description"] = "Senn channels the holy Light for 15 sec, inflicting 22,019 Holy damage to all players every 1 sec.",
},
[1233602] = {
["time"] = 1775242916,
["description"] = "Alleria marks a player, firing a silver-lined arrow through them. The arrow inflicts 143,637 Arcane damage in a line and removes Void effects from players and Voidspawn struck.",
},
[1272726] = {
["time"] = 1774316355,
["description"] = "Chimaerus slashes in the direction of a nearby target, inflicting 75,747 Physical damage to players in a frontal cone, causing them to bleed for 25,249 Physical damage every 1.5 sec for 6 sec and knocking them away.",
},
[1232470] = {
["time"] = 1775242916,
["description"] = "Ancient obelisks grasp a player with Void energy, inflicting 28,727 Shadow damage every 1 sec and reducing their movement speed by 50% for 8 sec. Upon removal, |cffffffffBursting Emptiness|r fires out through each obelisk.",
},
[1262036] = {
["time"] = 1775244980,
["description"] = "The Abyssal Voidshaper claims territory for Averzian, inflicting 235,042 Shadow damage to players within 12 yards and an additional 195,868 Shadow damage to players caught in the star burst blast.\r\n\r\nEach claimed territory brings Averzian's army closer to the |cffffffffMarch of the Endless|r.",
},
[1249251] = {
["time"] = 1775244980,
["description"] = "Averzian harnesses the Void, inflicting 74,429 Shadow damage to all players.\r\n\r\nHe then continues to radiate energy, inflicting 13,057 Shadow damage every 1 sec.",
},
[200183] = {
["time"] = 1775244485,
["description"] = "Reset the cooldown of your Holy Words, and enter a pure Holy form for 20 sec, increasing the cooldown reductions to your Holy Words by 200% and reducing their cost by 50%.",
},
[1245452] = {
["time"] = 1774316355,
["description"] = "Chimaerus sweeps across its den, exhaling corruption that inflicts 262,590 Nature damage to players standing in the area and stuns them for 1 sec.\r\n\r\nThe spewed corruption coalesces Manifestations and leaves behind |cffffffffAlndust Essence|r.",
},
[1246461] = {
["time"] = 1775242916,
["description"] = "The Rift Simulacrum strikes its current target with a draining touch, inflicting 313,891 Physical damage to the player and reducing all of their stats by 10% for 20 sec. This effect stacks.",
},
[1245391] = {
["time"] = 1775244338,
["description"] = "Ezzorak ejects a moving mass of pure darkness in a frontal direction, inflicting 39,173 to 117,521 Shadow damage to all players upon arrival, creating a Gloomfield.\r\n\r\nGloom damage done and the size of Gloomfield decreases up to 4 times as players contact the darkness, applying Gloomtouched.",
},
[1248983] = {
["time"] = 1774843171,
["description"] = "Lightblood marks several players then attempts to execute them 3 sec later, inflicting 1.1 million Holy damage split evenly among players within 8 yards of their location and increasing damage taken from Execution Sentence by 500% for 5 sec.\r\n\r\n3 Divine Hammers then spiral outward from the impact location.",
},
[1245645] = {
["time"] = 1775244338,
["description"] = "Ezzorak strikes his primary target, inflicting 376,669 Physical damage and 130,579 Shadow damage.\r\n\r\nThis attack empowers Ezzorak's melee attacks, causing them to absorb the next 24,813 healing. This effect stacks, increasing in intensity each Rakfang until Rakfang strikes a new target.",
},
[1250812] = {
["time"] = 1774843171,
["description"] = "Upon reaching 100 energy, Senn emanates a calming |cffffffffAura of Peace|r for 25 sec, protecting allies within 40 yards and pacifying any player who directly attacks them for 4 sec.\r\n\r\nUpon expiration, Senn consecrates the ground beneath her feet.",
},
[1238843] = {
["time"] = 1775242916,
["description"] = "Alleria calls upon the unending cosmos to consume her foes. Players caught within suffer 78,347 Shadow damage every 1 sec and receive 99% reduced healing and absorbs.",
},
[1245396] = {
["time"] = 1774316355,
["description"] = "Chimaerus consumes the essence of its enemies, inflicting 105,036 Nature damage every 2 sec for 10 sec.\r\n\r\nUpon finishing its channel, Chimaerus knocks players away and consumes any remaining Manifestations, casting |cffffffffCannibalized Essence|r for each Manifestation consumed.",
},
[1237837] = {
["time"] = 1775242916,
["description"] = "Celestial energy bursts around Alleria, inflicting 156,694 Shadow damage within 5 yards of each impact and calling forth an Undying Voidspawn.",
},
[1258880] = {
["time"] = 1775244980,
["description"] = "Averzian knocks back players and rains destruction onto the field at several destinations, inflicting 195,868 Shadow damage to players within 7 yards of the impact locations.",
},
[1251361] = {
["time"] = 1775244980,
["description"] = "Averzian summons Abyssal Voidshapers onto the battlefield. As his minions emerge, they inflict 195,868 Shadow damage to players within 10 yards and knocks them away.",
},
[1219531] = {
["time"] = 1773193474,
["description"] = "The Plexus Sentinel targets a player to be purged, firing a missile inflicting 641,916 Arcane damage split evenly between players within 6 yards.",
},
[1249748] = {
["time"] = 1775244338,
["description"] = "Upon reaching 100 energy, Ezzorak and Vaelgor fly as one, each spewing 130,579 Shadow damage to all players plus an additional 19,586 Shadow damage every 0.5 sec for 10 sec.",
},
[1251583] = {
["time"] = 1775244980,
["description"] = "With three adjacent portals empowering each other, Averzian tears open the void unleashing the endless march, inflicting 287,273 Shadow damage every 1 sec to players in its path.",
},
[1260712] = {
["time"] = 1775244980,
["description"] = "Averzian launches void lances outward, inflicting 195,868 Shadow damage to players in their path and knocking them back.",
},
[1245404] = {
["time"] = 1774316355,
["description"] = "Chimaerus descends to the ground, inflicting 75,747 Physical damage to all players upon landing and knocking them into the air.\r\n\r\nAny remaining Manifestations are consumed, causing Chimaerus to cast |cffffffffCannibalized Essence|r for each Manifestation consumed.",
},
[359816] = {
["time"] = 1774319765,
["description"] = "Take in a deep breath and fly to the targeted location, healing all allies in your path for 10,881 immediately, and 24,703 over 15 sec, reduced beyond 5 targets.\r\n\r\nRemoves all root effects. You are immune to movement impairing and loss of control effects.\r\n\r\nDamage taken while you are flying is absorbed, up to 100% of your maximum health.",
},
[1219450] = {
["time"] = 1773193474,
["description"] = "The Plexus Sentinel fires Arcane energy into players, inflicting 37,445 Arcane damage every 1 sec for 6 sec. Upon expiration, a |cffffffffDisplacement Matrix|r is created. ",
},
[1243981] = {
["time"] = 1775242916,
["description"] = "Uncontrolled silver-lined arrows fire from Alleria, inflicting 58,760 Arcane damage and removing Void effects from players struck. Being hit with an arrow increases damage taken from |cffffffffSilverstrike Barrage|r by 300% for 8 sec. This effect stacks.",
},
[1219263] = {
["time"] = 1773193474,
["description"] = "The Plexus Sentinel marks its current target, then fires an arcane charge that inflicts 401,198 Arcane damage to players within 10 yards, and 267,465 Arcane damage to all other players. Players farther from the target receive less damage. This explosion leaves behind |cffffffffPotent Mana Residue|r.\r\n\r\nThe impact causes the primary target to take 1,000% damage from |cffffffffObliteration Arcanocannon|r for 45 sec.",
},
[133] = {
["time"] = 1775155955,
["description"] = "Throws a fiery ball that causes 8,828 Fire damage.",
},
[1258514] = {
["time"] = 1774843171,
["description"] = "Senn emits a blinding flash of light, inflicting 207,007 Holy damage to all players and disorienting them for 5 sec.",
},
[1283236] = {
["time"] = 1775242916,
["description"] = "Alleria calls down a celestial body near a player. This energy crashes into the ground and inflicts 62,677 Shadow damage to all players. ",
},
[1265131] = {
["time"] = 1775244338,
["description"] = "Vaelgor buffets his primary target, knocking them away and inflicting 195,867 Shadow damage and 125,557 Physical damage. \r\n\r\nThis attack empowers Vaelgor's melee attacks, causing them to inflict 26,116 Shadow damage. This effect stacks, increasing in intensity each Vaelwing until Vaelwing strikes a new target.",
},
[1246736] = {
["time"] = 1774843171,
["description"] = "Lightblood passes judgment on his current target, inflicting 275,242 Holy damage and increasing damage they take from |cffffffffFinal Verdict|r by 300% for 5 sec.\r\n\r\nAfter passing judgment, Lightblood immediately casts Final Verdict on his current target.",
},
[1237614] = {
["time"] = 1775242916,
["description"] = "Alleria applies a Ranger Captain's Mark to random players within 40 yards for 6 sec. Upon expiration, she fires a |cffffffffSilverstrike Ricochet|r at them.",
},
[1264756] = {
["time"] = 1774316355,
["description"] = "Chimaerus causes several players within the Rift to succumb to madness, inflicting 52,517 Nature damage to players within 6 yards and horrifying them, causing them to suffer 13,129 Nature damage every 1 sec. This effect increases in intensity every 3 sec.\r\n\r\nAllies outside the Rift can stand nearby the victims to swap realms with them after a short duration, saving them from the madness.",
},
[1246487] = {
["time"] = 1774843171,
["description"] = "Bellamy targets several players with holy shields that explode on impact, inflicting 82,573 Holy damage plus an additional 48,167 Holy damage every 1 sec to players within 5 yards.",
},
[1246918] = {
["time"] = 1775242916,
["description"] = "A void barrier surrounds the Rift Simulacrum, absorbing damage equal to 15% of its maximum health. While this barrier persists, it inflicts 18,281 Shadow damage to all players every 1 sec.",
},
[1244221] = {
["time"] = 1775244338,
["description"] = "Vaelgor roars toward a targeted player, fearing players in a massive frontal cone. The dragon's breath inflicts 156,694 Shadow damage and an additional 78,347 Shadow damage every 3 sec, reducing movement speed by 30%, fearing them for 9 sec.",
},
[1239080] = {
["time"] = 1775242916,
["description"] = "Alleria marks players with a consuming arrow, reducing their healing received by 10% until they move 30 yards away from the arrow. This effect stacks, growing in intensity every 2 sec. \r\n\r\nUpon being removed, a Gravity Collapse is triggered.",
},
[1233865] = {
["time"] = 1775242916,
["description"] = "Alleria places a shell of Void magic around a player that absorbs 744,379 healing. If |cffffffffNull Corona|r is dispelled, the remaining absorb jumps to another random player.",
},
[1244917] = {
["time"] = 1775244338,
["description"] = "Ezzorak wreathes all players in shadow, inflicting 130,579 Shadow damage to players within 5 yards of each player.\r\n\r\nSummons a Voidorb at each players' location.",
},
[1249265] = {
["time"] = 1775244980,
["description"] = "Averzian collapses void energy around his target, inflicting 287,273 Shadow damage to all players. This damage is reduced by the number of players within 10 yards of the impact location.",
},
[1246165] = {
["time"] = 1774843171,
["description"] = "Upon reaching 100 energy, Bellamy emanates an |cffffffffAura of Devotion|r for 25 sec, reducing damage taken by 75% for allies within 40 yards.\r\n\r\nUpon expiration, Bellamy consecrates the ground beneath her feet.\r\n",
},
[1262623] = {
["time"] = 1775244338,
["description"] = "Vaelgor expels crystalline spacetime every 0.5 sec for 4 sec to players in a frontal direction. This outpouring inflicts 100,445 Physical damage plus an additional 3,917 Shadow damage every 0.5 sec for 8 sec. This effect stacks.\r\n\r\nUpon completion, the lattice shatters, forming a Nullzone and tethering all players. Nullzone's pull magnitude weakens as Nullbeam stacks, up to 8 times.",
},
[1248449] = {
["time"] = 1774843171,
["description"] = "Upon reaching 100 energy, Lightblood emanates an |cffffffffAura of Wrath|r for 15 sec, increasing Holy damage done by 100% for allies within 40 yards.\r\n\r\nUpon expiration, Lightblood consecrates the ground beneath his feet.",
},
[1246749] = {
["time"] = 1774843171,
["description"] = "Lightblood deems players within 100 yards unworthy, inflicting 165,146 Holy damage to them.",
},
[1249130] = {
["time"] = 1774843171,
["description"] = "Senn charges forward on her mighty elekk, inflicting 158,794 Physical damage to players in her path.",
},
[1280015] = {
["time"] = 1775244980,
["description"] = "Averzian marks several targets with a devouring void. Upon removal, applies |cffffffffLingering Darkness|r and consumes an application of |cffffffffCosmic Shell|r within 7 yards.",
},
[1251857] = {
["time"] = 1774843171,
["description"] = "Bellamy passes judgment on her current target, inflicting 275,242 Holy damage and increasing damage they take from |cffffffffShield of the Righteous|r by 300% for 5 sec.\r\n\r\nAfter passing judgment, Bellamy immediately casts |cffffffffShield of the Righteous|r on her current target.",
},
[1280458] = {
["time"] = 1775244338,
["description"] = "While flying, the dragon lashes their primary target in cosmic entanglement, inflicting between 78,347 and 783,473 Shadow damage, increasing in damage as distance between the dragon and their target increases.\r\n\r\nThe dragon then pulls the distant target nearby.",
},
[1248644] = {
["time"] = 1774843171,
["description"] = "Bellamy unleashes a volley of holy shields every 2 sec for 18 sec. Shields that hit players inflict 192,669 Holy damage and silence them for 5 sec.",
},
[1257087] = {
["time"] = 1774316355,
["description"] = "Chimaerus surrounds several players with ravenous energy, causing them to suffer $s1 Nature damage every $t1 sec for $d.\r\n\r\nUpon removal, the target erupts with $@spellname1257093 and consumes $@spellname1245857 within $1257093A1 yards.",
},
[1246653] = {
["time"] = 1774316355,
["description"] = "Chimaerus launches globs of phlegm at all players, inflicting 31,510 Nature damage every 1 sec for 20 sec.",
},
[1248710] = {
["time"] = 1774843171,
["description"] = "Senn brings |cffffffffTyr's Wrath|r down upon the 3 players nearest to her every 5 sec, absorbing the next 434,221 healing they receive. This effect stacks.",
},
[322118] = {
["time"] = 1774319762,
["description"] = "Summons an effigy of Yu'lon, the Jade Serpent for 25 sec. Yu'lon will heal injured allies with Soothing Breath, healing the target and up to 2 allies for 4,455 over 4.0 sec. \r\n\r\nEnveloping Mist costs 50% less mana while Yu'lon is active.",
},
[1276999] = {
["time"] = 1774843171,
["description"] = "Increases the caster's attack and movement speeds by 150% and all damage it deals by 500%.  Also grants immunity to Taunt effects.",
},
[1262289] = {
["time"] = 1774316355,
["description"] = "Chimaerus tears a hole in Reality, inflicting 378,737 Physical damage to its current target and 630,218 Nature damage split evenly between players within 10 yards of the impact.\r\n\r\nVictims are knocked into the air and gain |cffffffffAlnsight|r.",
},
},
